function solve(n: number, m: number, k: number): number {
    if (k === 0) return 0;
    if (k >= Math.max(n - 1, m - 1)) return 1;

    const rows = Math.max(0, n - 2 * k);
    const cols = Math.max(0, m - 2 * k);
    return Math.ceil((rows + cols) / 2);
}
